function rtfToTxt(rtf) {
  if (!rtf) return "";

  // 1. Supprimer complètement les définitions de police (\fonttbl {...})
  rtf = rtf.replace(/\\fonttbl[^}]+}/g, "");

  // 2. Supprimer les groupes spéciaux RTF comme \*\xxxx { ... }
  rtf = rtf.replace(/\\\*[^{}]+{|\\\*.*?}/g, "");

  // 3. Convertir les caractères Unicode (\u1234?)
  rtf = rtf.replace(/\\u(-?\d+)\?/g, (_, num) =>
    String.fromCharCode(parseInt(num))
  );

  // 4. Convertir les caractères hexa (\'B7 → ·, accent → é...)
  rtf = rtf.replace(/\\'([0-9a-fA-F]{2})/g, (_, hex) =>
    Buffer.from(hex, "hex").toString("latin1")
  );

  // 5. Remplacer les bullet points RTF (·) par "-"
  rtf = rtf.replace(/·/g, "- ");

  // 6. Sauts de ligne
  rtf = rtf.replace(/\\par[d]?/g, "\n");

  // 7. Supprimer commandes RTF (\b, \fs20, \f0, \cf1…)
  rtf = rtf.replace(/\\[a-zA-Z]+\d* ?/g, "");

  // 8. Supprimer accolades RTF
  rtf = rtf.replace(/[{}]/g, "");

  // 9. Nettoyage final
  rtf = rtf.replace(/\s+/g, " ").trim();

  return rtf;
}

// Récupérer les deux champs

const des = $input.first().json.Description;
const mis = $input.first().json.Missions;
const conn = $input.first().json.Connaissance;
const s_etre = $input.first().json.SavoirEtre;
const s_faire = $input.first().json.SavoirFaire;
const s_formation = $input.first().json.Formations;

// Conversion
const txt_des = rtfToTxt(des);
const txt_mis = rtfToTxt(mis);
const txt_conn = rtfToTxt(conn);
const txt_etre = rtfToTxt(s_etre);
const txt_faire = rtfToTxt(s_faire);
const txt_formation = rtfToTxt(s_formation);
// Retour
return [
  {
    json: {
      data_post:{
        Titre : $input.first().json.Titre,
        DESCTIPTION_txt: txt_des,
        MISSION_txt: txt_mis,
        CONNAISSANCE_txt: txt_conn,
        SAVOIR_ETRE_txt: txt_etre,
        SAVOIR_FAIRE_txt: txt_faire,
        FORMATION_txt: txt_formation
      }

    }
  }
];
